const body = $json.body || {};
const message = String(body.message || '').trim();
const phone = String(body.phone || '').replace(/[^\d]/g, '');
const locale = body.locale === 'en' ? 'en' : 'es';
const normalized = message.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
const wantsBooking = /\b(reservar|reserva|demo|cita|agendar|agenda|consultoria|consultoría|book|booking|appointment|schedule|calendar)\b/i.test(normalized);
const wantsReschedule = /\b(reagendar|reprogramar|cambiar hora|cambiar cita|otro horario|mover cita|reschedule|change appointment|another slot)\b/i.test(normalized);
const wantsCancel = /\b(cancelar|anular|cancel|cancellation)\b/i.test(normalized);
const isGreeting = /\b(hola|buenas|hey|hello|hi|good morning|good afternoon|good evening|buenos dias|buenas tardes|buenas noches)\b/i.test(normalized);
const isChannelQuestion = /\b(whatsapp|correo|correos|email|emails|mail|mails|responder whatsapp|responder correos|contestar whatsapp|contestar correos|parezca un bot|parecer un bot|sonar humano|human sounding|sound like a bot)\b/i.test(normalized);
const isPricingQuestion = /\b(cuanto cuesta|cuanto vale|precio|precios|tarifa|tarifas|coste|costes|pricing|price|prices|cost)\b/i.test(normalized);
const currentState = body.state || { intent: 'none', step: 'idle' };
const requestId = body.requestId || body.id || `${Date.now()}-${phone || 'unknown'}`;
if (!message || !phone) {
  return [{ json: { ok: false, skip: true, statusCode: 200, response: { ok: true, ignored: true, reason: 'missing message or phone' } } }];
}
const flags = { wantsBooking, wantsReschedule, wantsCancel, isGreeting, isChannelQuestion, isPricingQuestion };
const isBookingFlowStep = ['await_timezone', 'await_booking_id', 'await_booking_confirm', 'await_slot', 'await_email', 'await_email_confirm', 'await_phone', 'await_phone_confirm'].includes(currentState.step || '');
const needsBackend = wantsBooking || wantsReschedule || wantsCancel || isBookingFlowStep;
return [{ json: { ok: true, skip: false, requestId, message, text: message, phone, locale, wantsBooking, wantsReschedule, wantsCancel, history: Array.isArray(body.history) ? body.history : [], currentState, flags, route: { needsBackend }, body } }];

const original = $('Normalize WhatsApp Payload').first()?.json || {};
const source = $json || {};
const baseUrl = String($env.CLINVETIA_BASE_URL || 'https://clinvetia.com').replace(/\/+$/, '');
const demoUrl = `${baseUrl}/demo`;
const calculatorUrl = `${baseUrl}/calculadora`;
let reply = String(source.reply || source.output || source.text || source.response || '').replace(/\s+\n/g, '\n').trim();
if (!reply) {
  reply = original.locale === 'en'
    ? 'I can help with that. Tell me what you need and I will guide you.'
    : 'Puedo ayudarte con eso. Cuéntame qué necesitas y te guío.';
}
const needsWebContinuation = Boolean(original.wantsBooking || source.openCalendar || source.openRoiCalculator);
if (needsWebContinuation) {
  const url = source.openRoiCalculator && !original.wantsBooking ? calculatorUrl : demoUrl;
  const label = original.locale === 'en'
    ? `Continue here: ${url}`
    : `Sigue aquí: ${url}`;
  if (!reply.includes(url)) reply = `${reply}\n\n${label}`;
}
if (reply.length > 3500) reply = `${reply.slice(0, 3490).trim()}...`;
return [{ json: { phone: original.phone, reply, source, requestId: original.requestId } }];

const locale = $json.locale === 'en' ? 'en' : 'es';
const currentState = $json.currentState || {};
const flags = $json.flags || {};
const history = Array.isArray($json.history) ? $json.history.slice(-8) : [];
const transcript = history.map((item) => `${item.role}: ${String(item.content || '').replace(/\s+/g, ' ').trim()}`).join('\n');
const brief = flags.isGreeting && !flags.isChannelQuestion && !flags.isPricingQuestion;
const guidance = locale === 'en'
  ? 'Answer in English only. Sound human, concise and consultative. If the user is only greeting you, greet them naturally and ask one soft question about their clinic or what they need. If they ask about WhatsApp or email, explain clearly that Clinvetia can reply naturally, follow up, qualify leads and escalate to a human when appropriate. Answer the actual question first. Do not force a booking if the user is still exploring.'
  : 'Responde solo en espanol. Suena humana, breve y consultiva. Si el usuario solo saluda, saluda de forma natural y haz una sola pregunta suave sobre su clinica o sobre lo que necesita. Si pregunta por WhatsApp o correo, explica con claridad que Clinvetia puede responder con tono natural, hacer seguimiento, calificar leads y escalar a una persona cuando conviene. Responde primero a la duda real. No fuerces la reserva si el usuario aun esta explorando.';
const context = [
  `locale=${locale}`,
  `greeting=${Boolean(flags.isGreeting)}`,
  `channel_question=${Boolean(flags.isChannelQuestion)}`,
  `pricing_question=${Boolean(flags.isPricingQuestion)}`,
  `qualification_stage=${Number(currentState.qualificationStage || 0)}`,
  `lead_context=${currentState.leadContext || 'none'}`,
  `brief_mode=${brief}`
].join(' | ');
return [{ json: { chatInput: $json.text, sessionId: $json.body.sessionToken || $json.body.requestId || $json.body.pageUrl || 'moka-web-chat', locale, currentState, context, transcript, flags } }];

const source = $json || {};
const input = $('Prepare Agent Input').first()?.json || {};
const currentState = input.currentState || {};
const flags = input.flags || {};
const normalize = (value) => String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, ' ').replace(/\s+/g, ' ').trim();
const text = typeof source.output === 'string' ? source.output.trim() : typeof source.text === 'string' ? source.text.trim() : typeof source.response === 'string' ? source.response.trim() : '';
const fallbackReply = input.locale === 'en'
  ? 'I can help you understand how Clinvetia would fit your clinic and, if it makes sense, we can look at a demo.'
  : 'Puedo ayudarte a entender cómo encajaría Clinvetia en tu clínica y, si tiene sentido, vemos una demo.';
const normalizedInput = normalize(input.chatInput);
const normalizedReply = normalize(text);
const normalizedTranscript = normalize(input.transcript);
const isAffirmative = /\b(si|vale|ok|okey|claro|perfecto|de acuerdo|yes|sure|sounds good|me encaja)\b/.test(normalizedInput);
const wantsBookingNow = flags.wantsBooking || /\b(reservar|reserva|demo|cita|agendar|agenda|book|booking|appointment|schedule|calendario|calendar)\b/.test(normalizedInput);
const bookingContext = /\b(demo|consultoria|consultoría|horario|horarios|slot|slots|calendario|calendar|flujo de reserva|booking flow|reserva)\b/.test(normalizedTranscript);
const handsOffToBooking = /\b(flujo de reserva|booking flow|calendario|calendar|elige horario|elige franja|escoges la franja|choose a slot|pick a slot|completes los datos ahi|completes tus datos ahi|te llevo al flujo|abramos el flujo)\b/.test(normalizedReply);
const shouldHandoffToBackend = wantsBookingNow || handsOffToBooking || (isAffirmative && bookingContext);
const nextState = {
  intent: shouldHandoffToBackend ? 'none' : (currentState.intent || 'none'),
  step: shouldHandoffToBackend ? 'idle' : (currentState.step || 'idle'),
  proposedSlots: Array.isArray(currentState.proposedSlots) ? currentState.proposedSlots : [],
  selectedSlot: currentState.selectedSlot || null,
  email: currentState.email || null,
  phone: currentState.phone || null,
  targetBookingId: currentState.targetBookingId || null,
  targetBookingToken: currentState.targetBookingToken || null,
  city: currentState.city || null,
  objectionAttempts: Number(currentState.objectionAttempts || 0),
  qualificationStage: Math.max(1, Number(currentState.qualificationStage || 0)),
  leadContext: shouldHandoffToBackend ? '__demo_offer__' : (currentState.leadContext || null),
};
return [{ json: { reply: text || fallbackReply, state: nextState, handoffToBackend: shouldHandoffToBackend } }];
